import React from 'react';
import { motion } from 'framer-motion';

const Logo: React.FC<{ size?: 'small' | 'medium' | 'large' }> = ({ size = 'medium' }) => {
  const sizeClasses = {
    small: 'w-8 h-8',
    medium: 'w-12 h-12',
    large: 'w-16 h-16'
  };

  return (
    <motion.div
      className={`relative ${sizeClasses[size]}`}
      initial={{ rotate: 0 }}
      animate={{ rotate: 360 }}
      transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
    >
      <svg viewBox="0 0 100 100" className="w-full h-full">
        {/* House wireframe background */}
        <motion.path
          d="M20 80 L20 40 L50 20 L80 40 L80 80 Z"
          stroke="rgba(255, 255, 255, 0.1)"
          strokeWidth="1"
          fill="none"
          initial={{ pathLength: 0 }}
          animate={{ pathLength: 1 }}
          transition={{ duration: 2, ease: "easeInOut" }}
        />
        
        {/* First M - Black */}
        <motion.path
          d="M25 60 L25 35 L30 50 L35 35 L35 60 M45 60 L45 35 L50 50 L55 35 L55 60"
          stroke="#000000"
          strokeWidth="3"
          fill="none"
          initial={{ pathLength: 0, opacity: 0 }}
          animate={{ pathLength: 1, opacity: 1 }}
          transition={{ duration: 1.5, delay: 0.5, ease: "easeInOut" }}
        />
        
        {/* Second M - Brown */}
        <motion.path
          d="M40 55 L40 30 L45 45 L50 30 L50 55 M60 55 L60 30 L65 45 L70 30 L70 55"
          stroke="#8B4513"
          strokeWidth="3"
          fill="none"
          initial={{ pathLength: 0, opacity: 0 }}
          animate={{ pathLength: 1, opacity: 1 }}
          transition={{ duration: 1.5, delay: 0.8, ease: "easeInOut" }}
        />
      </svg>
    </motion.div>
  );
};

export default Logo;
